算法笔记二.​ 1.C++标准中，stdio.h 更推荐等价写法 cstdio ​ 2.数据类型 ​ 1.int 10的9次方 long long 10的18次方 ​ 2.char类型 小写字母比大写字母ASCII大32 ​ 3.bool在C++可以直接使用 C添加 stdbool.h 3.定义常量 const #define ​ 推荐const #define 只是直接将对应的部分替换，然后才进行编译和运行 4.scanf和printf ​ scanf ​ 1.除了char数组整个输入不加&amp;，其余类型都要加【也就是 %S 读入字符串 时候不加&amp;】 ​ 2. long long %lld double %lf ​ ​ printf ​ 1.double %f ​ 2. %md【空格补齐】 %0md 【0 补齐】 %.mf 【 保留xx位小数】 5.getchar putchar 6.math函数 ​ fabs(double x) 绝对值 ​ floor(double x) ceil(double x) 向下取整 向上取整 ​ pow(double r,double q) r的q次 ​ sqrt(double x) ​ log(double x) log e的对数 ​ round(double x) 四舍五入 7.数组 ​ 一般没有赋值都是随机值，所以要赋值可以{0} 都给个0 或者{ }什么都不写 ​ memset fill ​ memset(数组名，值，sizeof(数组名)) 【开头添加string.h】一般赋0 和 -1 因为memset 是 字节赋值 8.gets / puts ​ gets 输入一行字符串 【识别 
 作为输入结束】 ​ puts 输出一行字符串 并且接一个换行 9.string.h ​ strlen( 数组) 返回字符数组第一个\0以前的字符个数 ​ strcmp( 数组1，数组2) 返回字符串大小比较结果 比较原则是 按照字典顺序 ​ strcpy( 数组1，数组2) 复制给另一个数组，包括\0 ​ strcat( 数组1，数组2) 把2接到1后面 10 . sscanf sprintf ​ sscanf(screen,”%d”,&amp;n) screen 输入到 n ​ spcanf(screen,”%d”,n) n 输入到 screen 11.以数组作为函数参数 ​ 注：如果是一维则不需要填写长度，二维则需要填写 引用 ​ a.常量不可以使用引用，引用的符号&amp; 结构体 结构体里面能定义除了自己本身之外的任何数据类型。 【虽然不能定义自己，但可以定义自己的指针】 浮点数的比较 == 精度 pes 1e-8 圆周率acos（-1.0） 12.复杂度 ​ 三1. 123456789101112131415161718192021#include&lt;stdio.h&gt;int main() &#123; int a,sum; sum&#x3D;0; scanf(&quot;%d&quot;,&amp;a); while(a!&#x3D;1) &#123; if((a%2)&#x3D;&#x3D;0) &#123; a&#x3D;a&#x2F;2; &#125; else &#123; a&#x3D;(3*a)+1; a&#x3D;a&#x2F;2; &#125; sum++; &#125; printf(&quot;%d&quot;,sum); return 0;&#125; 12345678910111213141516171819202122#include&lt;stdio.h&gt;const int max &#x3D;100;int sco[max]&#x3D; &#123;0&#125;;int main() &#123; int n,id,sc; scanf(&quot;%d&quot;,&amp;n); while(n--) &#123; scanf(&quot;%d%d&quot;,&amp;id,&amp;sc); sco[id]+&#x3D;sc; &#125; int sum &#x3D; 0; int idm&#x3D;0; for(int i &#x3D; 0; i&lt;max; i++) &#123; if(sco[i]&gt;sum) &#123; sum&#x3D;sco[i]; idm&#x3D;i; &#125; &#125; printf(&quot;%d %d&quot;,idm,sum);&#125; 123456789101112131415161718192021222324252627282930#include&lt;stdio.h&gt;const int max &#x3D;200;int nu[max]&#x3D; &#123;0&#125;;int main() &#123; int n&#x3D;0; int i &#x3D;0 ; int co&#x3D;0; scanf(&quot;%d&quot;,&amp;n); co&#x3D;n; while(n--) &#123; scanf(&quot;%d&quot;,&amp;nu[i]); i++; &#125; int x &#x3D;0 ; i&#x3D;0; scanf(&quot;%d&quot;,&amp;x); while(co--) &#123; if(x&#x3D;&#x3D;nu[i]) &#123; printf(&quot;%d&quot;,i); break; &#125; if(co&#x3D;&#x3D;0) &#123; printf(&quot;-1&quot;); break; &#125; i++; &#125;&#125; ​ 注意 行间距比列间距要大 是本来就大 所以可以直接输出就行 12345678910111213141516171819202122232425262728293031#include&lt;stdio.h&gt;int main() &#123; int row,col; char c; scanf(&quot;%d %c&quot;,&amp;col,&amp;c); if(col % 2 &#x3D;&#x3D;1) row &#x3D; col &#x2F;2 +1; else row &#x3D; col &#x2F;2; for(int i &#x3D; 0; i &lt; col; i++) &#123; printf(&quot;%c&quot;,c); &#125; printf(&quot;
&quot;); for(int i &#x3D; 2; i&lt;row; i++) &#123; printf(&quot;%c&quot;,c); for(int j &#x3D; 0; j&lt;col-2; j++) &#123; printf(&quot; &quot;); &#125; printf(&quot;%c
&quot;,c); &#125; for(int i &#x3D; 0; i &lt; col; i++) &#123; printf(&quot;%c&quot;,c); &#125; return 0;&#125; 闰年 123bool isLeap()&#123; return (year % 4 &#x3D;&#x3D;0 &amp;&amp; year %100 !&#x3D; 0) || (year % 400 &#x3D;&#x3D; 0);&#125; 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748#include&lt;stdio.h&gt;int month[13][2]= &#123; &#123;0,0&#125;,&#123;31,31&#125;,&#123;28,29&#125;,&#123;31,31&#125;, &#123;30,30&#125;,&#123;31,31&#125;,&#123;30,30&#125;,&#123;31,31&#125;, &#123;31,31&#125;,&#123;30,30&#125;,&#123;31,31&#125;,&#123;30,30&#125;,&#123;31,31&#125;&#125;;bool isLeap(int year) &#123; return (year % 4 ==0 &amp;&amp; year %100 != 0) || (year % 400 == 0);&#125;int main() &#123; int t1,y1,m1,d1; int t2,y2,m2,d2; while(scanf(&quot;%d%d&quot;,&amp;t1,&amp;t2) !=EOF) &#123; if(t1&gt;t2) &#123; int temp = t1; t1=t2; t2=temp; &#125; y1=t1/10000; m1=(t1%10000)/100; d1=t1%100; y2=t2/10000; m2=(t2%10000)/100; d2=t2%100; int ans =1; while(y1&lt;y2||m1&lt;m2||d1&lt;d2) &#123; d1++; if(d1==month[m1][isLeap(y1)]+1) &#123; m1++; d1=1; &#125; if(m1==13) &#123; y1++; m1=1; &#125; ans++; &#125; printf(&quot;%d&quot;,ans); &#125; return 0;&#125; 12345678910111213141516171819202122#include&lt;stdio.h&gt;int main() &#123; int a,b,c; scanf(&quot;%d%d%d&quot;,&amp;a,&amp;b,&amp;c); int sum&#x3D;a+b; int nu[100]&#x3D; &#123;0&#125;; int i &#x3D; 0; while(sum!&#x3D;0) &#123; nu[i]&#x3D;sum%c; sum&#x3D;sum&#x2F;c; i++; &#125; for(i&#x3D;i-1; i&gt;&#x3D;0; i--) &#123; printf(&quot;%d&quot;,nu[i]); &#125; return 0;&#125; ​ 上面的这个 注意i=i-1 最后余数已经放进去了 但是还是加了一 所以先-1再进行计算 1234567891011121314151617181920212223242526272829303132333435#include&lt;stdio.h&gt;#include&lt;string.h&gt;int main() &#123; char a[20]; int i &#x3D;1; int w&#x3D;0; bool re&#x3D;true; while(gets(a)) &#123; i&#x3D;strlen(a); if(i%2&#x3D;&#x3D;0) &#123; for(int m &#x3D; 0; m&lt;(i&#x2F;2); m++) &#123; if(a[m]!&#x3D;a[i-m-1]) &#123; re&#x3D;false; &#125; &#125; &#125; else &#123; for(int m&#x3D;0; m&lt;(i&#x2F;2); m++) &#123; if(a[m]!&#x3D;a[i-m-1]) &#123; re&#x3D;false; &#125; &#125; &#125; if(re&#x3D;&#x3D;true) &#123; printf(&quot;YES&quot;); &#125; else &#123; printf(&quot;NO&quot;); &#125; &#125;&#125; 四1.选择排序 2.直接插入排序 六12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152#include&lt;stdio.h&gt;#include&lt;vector&gt;using namespace std;int main() &#123; vector&lt;int&gt; vi; for(int i &#x3D; 1; i&lt;&#x3D;5; i++) &#123; vi.push_back(i); &#125; vi.pop_back(); &#x2F;&#x2F;vector 的访问 1.下标 2.迭代器 printf(&quot;%d
&quot;,vi[0]); for(vector&lt;int&gt;::iterator it &#x3D; vi.begin(); it!&#x3D;vi.end(); it++) &#123; printf(&quot;%d &quot;,*it); &#125; printf(&quot;size&#x3D;%d
&quot;,vi.size()); &#x2F;&#x2F; vi.clear();&#x2F;&#x2F; for(vector&lt;int&gt;::iterator it &#x3D; vi.begin();it!&#x3D;vi.end();it++)&#123;&#x2F;&#x2F; printf(&quot;%d &quot;,*it);&#x2F;&#x2F; &#125; vi.insert(vi.begin(),-1); for(vector&lt;int&gt;::iterator it &#x3D; vi.begin(); it!&#x3D;vi.end(); it++) &#123; printf(&quot;%d &quot;,*it); &#125; printf(&quot;
&quot;); vi.erase(vi.begin()); for(vector&lt;int&gt;::iterator it &#x3D; vi.begin(); it!&#x3D;vi.end(); it++) &#123; printf(&quot;%d &quot;,*it); &#125; printf(&quot;
&quot;); vi.erase(vi.begin(),vi.begin()+1); for(vector&lt;int&gt;::iterator it &#x3D; vi.begin(); it!&#x3D;vi.end(); it++) &#123; printf(&quot;%d &quot;,*it); &#125;&#125; 分数约分 12345678910111213141516171819#include&lt;iostream&gt;#include&lt;cstdio&gt;using namespace std; &#x2F;&#x2F;递归求出分子和分母的最大公约数 int Gcd(int m,int n)&#123; if(n&#x3D;&#x3D;0) return m; return Gcd(n,m%n);&#125; int main()&#123; int a,b; char op; scanf(&quot;%d%c%d&quot;,&amp;a,&amp;op,&amp;b); cout&lt;&lt;a&lt;&lt;&quot;&#x2F;&quot;&lt;&lt;b&lt;&lt;&quot;的最简分数为：&quot;; cout&lt;&lt;a&#x2F;Gcd(a,b)&lt;&lt;&quot;&#x2F;&quot;&lt;&lt;b&#x2F;Gcd(a,b)&lt;&lt;endl; return 0; &#125; 高精度 高精度加法#题目描述#输入两个大整数a，b，输出他们的和。（1&lt;=a,b&lt;=10的100次方） 输入#输入两个大整数a和b。 输出#输入a加b的和。 样例输入#1Copy43434343445435343 32435647668754353 样例输出#1Copy75869991114189696 程序+注释#1234567891011121314151617181920212223242526272829303132333435Copy#include &lt;bits&#x2F;stdc++.h&gt;using namespace std;char al[100],bl[100]; int a[100],b[100],c[100];int main()&#123; scanf(&quot;%s&quot;,al);&#x2F;&#x2F;不能用gets scanf(&quot;%s&quot;,bl);&#x2F;&#x2F;因为这两个数之间只有一个空格 int lena,lenb,lenc,x &#x3D; 0;&#x2F;&#x2F;x代表进位 lena &#x3D; strlen(al);&#x2F;&#x2F;lena是al数组的长度 lenb &#x3D; strlen(bl);&#x2F;&#x2F;lenb是bl数组的长度 for (int i &#x3D; 0;i &lt;&#x3D; lena - 1;i ++)&#x2F;&#x2F;把这个数字反着存储 al里的123就是a里面的321 a[lena - i] &#x3D; al[i] - &#39;0&#39;; for (int i &#x3D; 0;i &lt;&#x3D; lenb - 1;i ++)&#x2F;&#x2F;这个也是 b[lenb - i] &#x3D; bl[i] - &#39;0&#39;; lenc &#x3D; 1;&#x2F;&#x2F;循环变量 while ((lenc &lt;&#x3D; lena) || (lenc &lt;&#x3D; lenb))&#x2F;&#x2F;循环直到lenc等于al或者bl的长度 &#123; c[lenc] &#x3D; a[lenc] + b[lenc] + x;&#x2F;&#x2F;（核心）把这两个数字加起来，并且加上进位 x &#x3D; c[lenc] &#x2F; 10;&#x2F;&#x2F;如果两个数加起来大于10，x就是1，否则取余的结果就是 0 c[lenc] &#x3D; c[lenc] % 10;&#x2F;&#x2F; lenc ++;&#x2F;&#x2F;自增 1 &#125; c[lenc] &#x3D; x;&#x2F;*把最后一位进位过来*&#x2F; while (c[lenc] &#x3D;&#x3D; 0)&#x2F;&#x2F;如果最后一位为零 &#123; lenc --;&#x2F;&#x2F;把最后一位不输出 &#125; for (int i &#x3D; lenc;i &gt;&#x3D; 1;i --)&#x2F;&#x2F;输出 &#123; cout &lt;&lt; c[i]; &#125; cout &lt;&lt; endl;&#x2F;&#x2F;回车 return 0;&#125; 高精度减法#题目描述#输入两个大整数a，b，输出他们的差。（1&lt;=a,b&lt;=10的100次方） 输入#输入两个大整数a和b。 输出#输入a减b的差。 样例输入#1Copy35 45 样例输出#1Copy-10 程序+注释#1234567891011121314151617181920212223242526272829303132333435363738394041Copy#include &lt;bits&#x2F;stdc++.h&gt;using namespace std;char s1[1000],s2[1000];int a[1000],b[1000],c[1000];int main()&#123; char n[1000]; scanf(&quot;%s %s&quot;,s1,s2);&#x2F;&#x2F;也不能用gets if (strlen(s1) &lt; strlen(s2) || strlen(s1) &#x3D;&#x3D; strlen(s2) &amp;&amp; strcmp(s1,s1) &lt; 0)&#x2F;&#x2F; 如果减数 大于 被减数 &#123; strcpy(n,s1);strcpy(s1,s2);strcpy(s2,n);&#x2F;&#x2F;把s1 和 s2 交换 printf(&quot;-&quot;);&#x2F;&#x2F;打印出“- ” 这个符号 &#125; int len1 &#x3D; strlen(s1);&#x2F;&#x2F;s1 的长度 int len2 &#x3D; strlen(s2);&#x2F;&#x2F;s2 的长度 for (int i &#x3D; len1 - 1;i &gt;&#x3D; 0;i --)&#x2F;&#x2F;反着存储 &#123; a[len1 - (i + 1) + 1] &#x3D; s1[i] - &#39;0&#39;; &#125; for (int i &#x3D; len2 - 1;i &gt;&#x3D; 0;i --)&#x2F;&#x2F;反着存储 &#123; b[len2 - (i + 1) + 1] &#x3D; s2[i] - &#39;0&#39;; &#125; for (int i &#x3D; 1;i &lt;&#x3D; len1;i ++) &#123; a[i] &#x3D; a[i] - b[i];&#x2F;&#x2F;标准减法，把 a[i] - b[i] 的结果存在 a[i] 里面 if (a[i] &lt; 0)&#x2F;&#x2F;退位 &#123; a[i] &#x3D; a[i] + 10; a[i + 1] --; &#x2F;&#x2F;后面的一位自减1 &#125; &#125; while (a[len1] &#x3D;&#x3D; 0)&#x2F;&#x2F;如果最后一位为零 &#123; len1 --;&#x2F;&#x2F;把最后一位不输出 &#125; for (int i &#x3D; len1;i &gt;&#x3D; 1;i --)&#x2F;&#x2F;输出 &#123; printf (&quot;%d&quot;,a[i]);&#x2F;&#x2F;输出 &#125;&#125; 题目描述用高精度计算出S=1!+2!+3!+…+n! (n≤50)S=1!+2!+3!+…+n!(n≤50) 其中“!”表示阶乘，例如：5!=5 	imes 4 	imes 3 	imes 2 	imes 15!=5×4×3×2×1。 输入格式一个正整数NN。 输出格式一个正整数SS，表示计算结果。 输入输出样例输入 #1复制 13 输出 #1复制 19 123456789101112131415161718192021222324252627282930313233343536373839404142#include&lt;bits&#x2F;stdc++.h&gt;using namespace std;int a[2000];int c[2000];void pplus(int *a,int *c) &#123; int jw&#x3D;0; for(int i&#x3D;1; i&lt;&#x3D;1000; i++) &#123; c[i]+&#x3D;a[i]+jw; jw&#x3D;c[i]&#x2F;10; c[i]%&#x3D;10; &#125;&#125;void cheng(int *a,int c) &#123; int jw&#x3D;0; for(int i&#x3D;1; i&lt;&#x3D;1000; i++) &#123; a[i]&#x3D;a[i]*c+jw; jw&#x3D;a[i]&#x2F;10; a[i]%&#x3D;10; &#125;&#125;int main() &#123; int n; cin&gt;&gt;n; a[1]&#x3D;1; for(int i&#x3D;1; i&lt;&#x3D;n; i++) &#123; cheng(a,i); pplus(a,c); &#125; bool flag&#x3D;0; for(int i &#x3D; 1000; i&gt;&#x3D;1; i--) &#123; if(c[i]!&#x3D;0) flag&#x3D;1; if(flag) cout&lt;&lt;c[i]; &#125; return 0;&#125; 输入格式每个输入文件包含若干行字符串，字符串有大写的W、L和E组成。其中EE表示比赛信息结束，程序应该忽略E之后的所有内容。 1234567891011#include&lt;bits&#x2F;stdc++.h&gt;using namespace std;char ch,s[62510]&#x2F;&#x2F;至于为什么是62510看说明提示;int a,b,emm&#x2F;&#x2F;emm表示分数总数量（同时也是下标）a,b下文会讲;int main()&#123; while(cin&gt;&gt;ch)&#123;&#x2F;&#x2F;一直输入 if(ch&#x3D;&#x3D;&#39;E&#39;)break;&#x2F;&#x2F;如果是E就结束（防止E不是最后一个字符这一情况发生） else s[++emm]&#x3D;ch;&#x2F;&#x2F;存入字符数组中 &#125; &#x2F;&#x2F;awa&#125;
